<span class="line"><span class="token function">print</span><span class="token punctuation">(</span><span class="token function">describe</span><span class="token punctuation">(</span><span class="token number">5</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 其他</span></span>
